const allItems = $input.all();
const keywords = ['claude', 'chatgpt', 'gemini', 'openai', 'grok', 'anthropic', 'copilot', 'ai模型', '生成式', '人工智慧', 'llm', 'sora', 'deepseek', '大模型', 'ai助理', '機器學習', '深度學習', 'ai創作'];
const now = new Date();
const taiwanNow = new Date(now.getTime() + 8 * 60 * 60 * 1000);
const todayStr = taiwanNow.toISOString().split('T')[0];

function getDateTW(pub) {
  if (!pub) return null;
  try {
    const d = new Date(pub);
    if (isNaN(d.getTime())) return null;
    return new Date(d.getTime() + 8 * 60 * 60 * 1000);
  } catch(e) { return null; }
}

function scoreItem(item) {
  const title = (item.json.title || '').toLowerCase();
  const content = (item.json.contentSnippet || item.json.content || '').toLowerCase();
  return keywords.reduce((acc, kw) => acc + (title.includes(kw) ? 3 : 0) + (content.includes(kw) ? 1 : 0), 0);
}

const todayItems = allItems.filter(item => {
  const d = getDateTW(item.json.pubDate || item.json.isoDate);
  return d && d.toISOString().split('T')[0] === todayStr;
});

let pool, period;
if (todayItems.length > 0) {
  pool = todayItems;
  period = 'today';
} else {
  const weekAgo = new Date(taiwanNow.getTime() - 7 * 24 * 60 * 60 * 1000);
  const weekItems = allItems.filter(item => {
    const d = getDateTW(item.json.pubDate || item.json.isoDate);
    return d && d >= weekAgo;
  });
  if (weekItems.length === 0) { return []; }
  pool = weekItems;
  period = 'week';
}

const seen = new Set();
const unique = pool.filter(item => {
  const key = (item.json.title || '').substring(0, 30);
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const scored = unique.map(item => ({ score: scoreItem(item), json: item.json }));
scored.sort((a, b) => b.score - a.score);
const top5 = scored.slice(0, 5);

// === 靜態資料去重 ===
const staticData = $getWorkflowStaticData('global');
const sentLinks = new Set(staticData.sentLinks || []);

const articles = top5
  .map(item => ({
    title: (item.json.title || '無標題').substring(0, 80),
    link: item.json.link || item.json.guid || ''
  }))
  .filter(a => !sentLinks.has(a.link));

if (articles.length === 0) {
  console.log('所有文章已發送過，略過');
  return [];
}

// 記錄已發送（保留最多 100 筆）
staticData.sentLinks = [
  ...(staticData.sentLinks || []),
  ...articles.map(a => a.link)
].slice(-100);

const titleList = articles.map((a, i) => (i+1) + '. ' + a.title).join('\n');
const prompt = '請用繁體中文，為以下每則AI新聞標題各寫一句話重點摘要（不超過35字）。\n格式：只回傳「編號. 摘要」，不要重複標題文字。\n\n新聞標題：\n' + titleList;
return [{ json: { articles, prompt, period } }];

const filterData = $('篩選今日新聞').first().json;
const articles = filterData.articles || [];
const period = filterData.period || 'today';
const geminiText = $json.text || '';
const lines = geminiText.split('\n');
const summaries = [];
for (const line of lines) {
  const m = line.trim().match(/^(\d+)[.、:：]\s*(.+)/);
  if (m) summaries[parseInt(m[1]) - 1] = m[2].trim();
}
const today = new Date().toLocaleDateString('zh-TW', { timeZone: 'Asia/Taipei', year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' });
const periodNote = period === 'week' ? '（本週新聞）\n\n' : '';
const header = '🤖 **AI 科技新聞快報** 📰\n📅 ' + today + '\n\n' + periodNote;
const footer = '\n> 資料來源：科技新報 & TechOrange';
const MAX = 1900;
let parts = [], totalLen = header.length + footer.length;
for (let i = 0; i < articles.length; i++) {
  const title = articles[i].title, link = articles[i].link;
  const summary = summaries[i] || '';
  const part = '**' + (i+1) + '. ' + title + '**\n' + (summary ? summary + '\n' : '') + link;
  const addLen = part.length + (parts.length > 0 ? 2 : 0);
  if (totalLen + addLen > MAX) break;
  parts.push(part); totalLen += addLen;
}
const content = header + parts.join('\n\n') + footer;
return [{ json: { content } }];
